update chat_tbl
set is_read = 1
where receiver_id = #{memberId}
  and sender_id = #{partnerId}
  and is_read = 0
  and deleted_yn = 0

update chat_tbl
set sender_hidden_at = CURRENT_TIMESTAMP(6)
where sender_id = #{memberId}
  and receiver_id = #{partnerId}

update chat_tbl
set receiver_hidden_at = CURRENT_TIMESTAMP(6)
where sender_id = #{partnerId}
  and receiver_id = #{memberId}
